-- Input Validation and Sanitization at Database Level\n\n-- 1. Function to sanitize profile fields (Security Definer)\nCREATE OR REPLACE FUNCTION public.sanitize_profile_input()\nRETURNS trigger\nLANGUAGE plpgsql\nSECURITY DEFINER\nAS c:\Users\shaik\Downloads\foliogen\nBEGIN\n    -- Strip script tags and other dangerous HTML from bio, headline, and fullName\n    NEW.full_name := regexp_replace(NEW.full_name, '<[^>]*>', '', 'g');\n    NEW.headline := regexp_replace(NEW.headline, '<[^>]*>', '', 'g');\n    NEW.bio := regexp_replace(NEW.bio, '<[^>]*>', '', 'g');\n    \n    -- Limit field lengths at database level as secondary gate\n    NEW.full_name := substring(NEW.full_name FROM 1 FOR 200);\n    NEW.headline := substring(NEW.headline FROM 1 FOR 300);\n    NEW.bio := substring(NEW.bio FROM 1 FOR 3000);\n\n    -- Enforce URL format for photo_url if exists\n    IF NEW.photo_url IS NOT NULL AND NEW.photo_url !~ '^https?://' THEN\n        NEW.photo_url := NULL;\n    END IF;\n\n    -- Enforce email format\n    IF NEW.email IS NOT NULL AND NEW.email !~ '^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$' THEN\n        NEW.email := OLD.email; -- Reject update if invalid\n    END IF;\n\n    RETURN NEW;\nEND;\nc:\Users\shaik\Downloads\foliogen;\n\n-- 2. Trigger for profile sanitization\nDROP TRIGGER IF EXISTS tr_sanitize_profile ON public.profiles;\nCREATE TRIGGER tr_sanitize_profile\nBEFORE INSERT OR UPDATE ON public.profiles\nFOR EACH ROW\nEXECUTE FUNCTION public.sanitize_profile_input();\n\n-- 3. Policy for secure file uploads (Handled in storage config, but re-locking here)\n-- Ensuring only owner can delete/update files in their own folder\nDROP POLICY IF EXISTS " Users can update their own project documents\ ON storage.objects;\nCREATE POLICY \Users can update their own project documents\ ON storage.objects\nFOR UPDATE TO authenticated\nUSING (bucket_id = 'project_documents' AND (storage.foldername(name))[1] = auth.uid()::text);\n